examples.code:
-- Creating roles
CREATE ROLE clerk;
CREATE ROLE manager;
CREATE ROLE admin;

-- Granting privileges to roles
GRANT SELECT ON employees TO clerk;
GRANT SELECT, INSERT ON employees TO manager;
GRANT ALL PRIVILEGES ON employees TO admin;

-- Assigning roles to users
GRANT clerk TO john;
GRANT manager TO sarah;
GRANT admin TO database_admin;

-- Grant with option to allow further delegation
GRANT SELECT ON accounts TO manager WITH GRANT OPTION;

-- Revoking privileges
REVOKE INSERT ON employees FROM manager;
REVOKE clerk FROM john;
